#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <stdbool.h>

#define KMER_SIZE 19
#define HASH_SIZE 100003
#define MAX_LINE 256

typedef struct kmer_node {
    char kmer[KMER_SIZE + 1];
    char left_ext;
    char right_ext;
    bool visited;
    struct kmer_node *next;
} kmer_node_t;

typedef struct {
    kmer_node_t **table;
    int size;
} hash_table_t;

unsigned int hash_function(const char *kmer) {
    unsigned int hash = 5381;
    for (int i = 0; i < KMER_SIZE; i++) {
        hash = ((hash << 5) + hash) + kmer[i];
    }
    return hash % HASH_SIZE;
}

hash_table_t *create_hash_table() {
    hash_table_t *ht = malloc(sizeof(hash_table_t));
    ht->table = calloc(HASH_SIZE, sizeof(kmer_node_t*));
    ht->size = HASH_SIZE;
    return ht;
}

void insert_kmer(hash_table_t *ht, const char *kmer, char left_ext, char right_ext) {
    unsigned int index = hash_function(kmer);
    kmer_node_t *new_node = malloc(sizeof(kmer_node_t));
    strcpy(new_node->kmer, kmer);
    new_node->left_ext = left_ext;
    new_node->right_ext = right_ext;
    new_node->visited = false;
    new_node->next = ht->table[index];
    ht->table[index] = new_node;
}

kmer_node_t *find_kmer(hash_table_t *ht, const char *kmer) {
    unsigned int index = hash_function(kmer);
    kmer_node_t *current = ht->table[index];
    while (current) {
        if (strcmp(current->kmer, kmer) == 0) {
            return current;
        }
        current = current->next;
    }
    return NULL;
}

char *get_next_kmer(const char *current_kmer, char extension) {
    if (extension == 'F') return NULL;

    char *next_kmer = malloc(KMER_SIZE + 1);
    strncpy(next_kmer, current_kmer + 1, KMER_SIZE - 1);
    next_kmer[KMER_SIZE - 1] = extension;
    next_kmer[KMER_SIZE] = '\0';
    return next_kmer;
}

char *get_prev_kmer(const char *current_kmer, char extension) {
    if (extension == 'F') return NULL;

    char *prev_kmer = malloc(KMER_SIZE + 1);
    prev_kmer[0] = extension;
    strncpy(prev_kmer + 1, current_kmer, KMER_SIZE - 1);
    prev_kmer[KMER_SIZE] = '\0';
    return prev_kmer;
}

void traverse_and_build_contig(hash_table_t *ht, kmer_node_t *start, FILE *output) {
    if (start->visited) return;

    char *contig = malloc(100000);
    strcpy(contig, start->kmer);
    start->visited = true;

    // Extend right
    kmer_node_t *current = start;
    while (current->right_ext != 'F') {
        char *next_kmer_str = get_next_kmer(current->kmer, current->right_ext);
        if (!next_kmer_str) break;

        kmer_node_t *next = find_kmer(ht, next_kmer_str);
        free(next_kmer_str);

        if (!next || next->visited) break;

        int len = strlen(contig);
        contig[len] = current->right_ext;
        contig[len + 1] = '\0';

        next->visited = true;
        current = next;
    }

    // Extend left
    current = start;
    char *left_part = malloc(100000);
    left_part[0] = '\0';

    while (current->left_ext != 'F') {
        char *prev_kmer_str = get_prev_kmer(current->kmer, current->left_ext);
        if (!prev_kmer_str) break;

        kmer_node_t *prev = find_kmer(ht, prev_kmer_str);
        free(prev_kmer_str);

        if (!prev || prev->visited) break;

        char temp[100000];
        sprintf(temp, "%c%s", current->left_ext, left_part);
        strcpy(left_part, temp);

        prev->visited = true;
        current = prev;
    }

    // Combine left and right parts
    char *final_contig = malloc(200000);
    sprintf(final_contig, "%s%s", left_part, contig);

    if (strlen(final_contig) >= KMER_SIZE) {
        fprintf(output, "%s\n", final_contig);
    }

    free(contig);
    free(left_part);
    free(final_contig);
}

int main(int argc, char *argv[]) {
    if (argc != 2) {
        fprintf(stderr, "Usage: %s <input_file>\n", argv[0]);
        return 1;
    }

    FILE *input = fopen(argv[1], "r");
    if (!input) {
        perror("Error opening input file");
        return 1;
    }

    FILE *output = fopen("/app/serial.out", "w");
    if (!output) {
        perror("Error opening output file");
        fclose(input);
        return 1;
    }

    hash_table_t *ht = create_hash_table();
    char line[MAX_LINE];

    // Read and insert all k-mers
    while (fgets(line, MAX_LINE, input)) {
        char kmer[KMER_SIZE + 1];
        char extensions[3];

        if (sscanf(line, "%s\t%s", kmer, extensions) == 2) {
            insert_kmer(ht, kmer, extensions[0], extensions[1]);
        }
    }

    fclose(input);

    // Traverse and build contigs
    for (int i = 0; i < HASH_SIZE; i++) {
        kmer_node_t *current = ht->table[i];
        while (current) {
            if (!current->visited) {
                traverse_and_build_contig(ht, current, output);
            }
            current = current->next;
        }
    }

    fclose(output);
    printf("Serial de Bruijn graph construction completed. Output written to /app/serial.out\n");
    return 0;
}
EOF
