    char *threads_env = getenv("UPC_THREADS");
    if (threads_env) {
        THREADS = atoi(threads_env);
    }

    if (THREADS <= 0 || THREADS > MAX_THREADS) {
        THREADS = 1;
    }

    FILE *input = fopen(argv[1], "r");
    if (!input) {
        perror("Error opening input file");
        return 1;
