            thread_data[i].output = output;
            thread_data[i].output_mutex = &output_mutex;

            pthread_create(&threads[i], NULL, thread_function, &thread_data[i]);
        }

        for (int i = 0; i < THREADS; i++) {
            pthread_join(threads[i], NULL);
        }
