bool mark_visited(hash_table_t *ht, const char *kmer) {
    unsigned int index = hash_function(kmer);
    pthread_mutex_lock(&ht->mutexes[index]);

    kmer_node_t *current = ht->table[index];
    while (current) {
        if (strcmp(current->kmer, kmer) == 0) {
            if (current->visited) {
                pthread_mutex_unlock(&ht->mutexes[index]);
                return false;
            }
            current->visited = true;
            pthread_mutex_unlock(&ht->mutexes[index]);
            return true;
        }
        current = current->next;
    }

    pthread_mutex_unlock(&ht->mutexes[index]);
    return false;
}

void traverse_and_build_contig(hash_table_t *ht, kmer_node_t *start, FILE *output) {
    if (!mark_visited(ht, start->kmer)) return;

    char *contig = malloc(100000);
    strcpy(contig, start->kmer);

    kmer_node_t *current = start;
    while (current->right_ext != 'F') {
        char *next_kmer_str = get_next_kmer(current->kmer, current->right_ext);
