        kmer_node_t *next = find_kmer(ht, next_kmer_str);
        if (!next || !mark_visited(ht, next_kmer_str)) {
            free(next_kmer_str);
            break;
        }

        int len = strlen(contig);
        contig[len] = current->right_ext;
        contig[len + 1] = '\0';

        current = next;
        free(next_kmer_str);
    }
